class Solution {
    public int countVowelPermutation(int n) {
        final int MOD = (int)1e9 + 7;
        long[] a = new long[5];
        long[] b = new long[5];
        a[0] = a[1] = a[2] = a[3] = a[4] = 1;
        for (int i = 2; i <= n; i++) {
            b[0] = a[1];
            b[1] = (a[0] + a[2]) % MOD;
            b[2] = (a[0] + a[1] + a[3] + a[4]) % MOD;
            b[3] = (a[2] + a[4]) % MOD;
            b[4] = a[0];
            long[] temp = a;
            a = b;
            b = temp;
        }
        long res = 0;
        for (long x : a) res = (res + x) % MOD;
        return (int)res;
    }
}
